SELECT MAX(P.Incasso) AS MassimoIncasso
FROM FILM F INNER JOIN PROIEZIONI P ON F.CodFilm = P.CodFilm
WHERE F.Genere IN ('Fantascienza','Fantasy') AND P.DataProiezione NOT BETWEEN '2025-01-01' AND '2025-12-31';
